#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        double total = 0.0, val;
        for (int i = 0; i < N; ++i) {
            scanf("%lf", &val);
            total += val;
        }
        // %g prints without unnecessary trailing zeros
        printf("The total amount spent is: %g\n", total);
    }
    return 0;
}

