#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        total = 0.0
        for _ in range(N):
            total += float(next(it))
        out_lines.append(f"The total amount spent is: {total}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

